import{_ as i,c as a,o as e,a7 as r}from"./chunks/framework.Vx-M4LRp.js";const f=JSON.parse('{"title":"尖椒鸡","description":"","frontmatter":{},"headers":[],"relativePath":"blog/life/菜谱.md","filePath":"blog/life/菜谱.md","lastUpdated":1777214504000}'),o={name:"blog/life/菜谱.md"};function t(n,l,s,h,d,c){return e(),a("div",null,[...l[0]||(l[0]=[r('<p><a href="https://sspai.com/prime/story/vlogs-for-learning-to-cook" target="_blank" rel="noreferrer">想学做饭，从哪些视频博主开始入门</a></p><h1 id="尖椒鸡" tabindex="-1">尖椒鸡 <a class="header-anchor" href="#尖椒鸡" aria-label="Permalink to “尖椒鸡”">​</a></h1><ol><li>新鲜的鸡肉，剁小块前洗干净，剁小之后就不见水</li><li>葱、姜、蒜、小米辣、绿尖椒、鲜花椒（干花椒）</li><li>油（可以稍微多点，不然水分都炒不出去）烧热后，倒入鸡，先不要翻动，等受热后再翻</li><li>受热后不停的翻动，把多余的水分炒出去，把肉煸香，有焦边的时候就可以了（如果油多可以舀出去）</li><li>倒入料头（第二步中的内容除了绿尖椒都倒入），炒出香味</li><li>沿着锅边倒入生抽、黄酒、少量放点醋，（五香粉）、白胡椒、盐巴</li><li>倒入绿辣椒，炒熟出锅</li></ol><h1 id="排骨烧土豆" tabindex="-1">排骨烧土豆 <a class="header-anchor" href="#排骨烧土豆" aria-label="Permalink to “排骨烧土豆”">​</a></h1><ol><li>排骨洗干净，直接倒入油锅中，先要翻，等他受一会热再翻动（不要七翻八翻的，受热不均匀的时候会粘锅）</li><li>炒排骨到边缘有焦黄的状态（把肉的香味炒出来）</li><li>倒入生姜、大葱、桂皮、八角、干辣椒</li><li>沿着锅边来一圈黄酒、生抽，再来一点老抽上色、可以再加两颗冰糖</li><li>炒上色之后，加热水，水开后转成小火炖25分钟左右</li><li>调味放盐、胡椒粉</li><li>倒入土豆，再焖十分钟</li><li>转成大火收汁（汁多就舀出来一些）</li><li>出锅前来点辣椒段或者蒜苗段都可以</li></ol><h1 id="肥肠鸡" tabindex="-1">肥肠鸡 <a class="header-anchor" href="#肥肠鸡" aria-label="Permalink to “肥肠鸡”">​</a></h1><ol><li>肥肠 鸡 一起炒 （肥肠需要洗净焯水去腥料酒，鸡血水洗干净即可，不需要焯水）先肥肠，后鸡</li><li>炒出香味后，在放姜蒜（粗点的颗粒），炒出香味</li><li>豆瓣，炒出红油</li><li>根据自己口味放适量的火锅底料（牛油），炒化，炒香，+料酒</li><li>加水，慢慢烧，根据鸡的年限，越老的鸡，烧的时间越久，期间可加入配菜（土豆 芋头 青笋等…芋头单独处理煮熟会更好），市场买的普通鸡一般三十分钟到四十分钟就好了。</li><li>出锅撒上葱段，香菜即可</li></ol><h1 id="粉丝蒜蓉虾" tabindex="-1">粉丝蒜蓉虾 <a class="header-anchor" href="#粉丝蒜蓉虾" aria-label="Permalink to “粉丝蒜蓉虾”">​</a></h1><ol><li>粉丝热水泡软</li><li>虾处理干净（虾线，去壳，留虾尾）</li><li>蒜蓉酱（直接买做好的蒜蓉辣椒，也可以自己做，蒜剁碎，小米辣剁碎，泼热油，加入耗油，生抽，白糖调味）</li><li>摆盘，粉丝垫底，放入虾，每一只虾都加入蒜蓉酱</li><li>热水，蒸五分钟</li><li>蒸好后，撒葱花，生抽（或者蒸鱼豉油），最后淋上热油！</li></ol><h1 id="红烧牛肉" tabindex="-1">红烧牛肉 <a class="header-anchor" href="#红烧牛肉" aria-label="Permalink to “红烧牛肉”">​</a></h1><ol><li>买那种两边都有筋的牛肉（牛腩或者牛肋条），切稍微大块（煮了之后要缩水）</li><li>用冷水加入牛肉焯水，加生姜、葱（小葱、大葱都可以）、黄酒（料酒）去腥，水开之后去捞出血沫，把牛肉捞出沥水</li><li>新鲜牛肉可以留下原汤，冻牛肉就不用留原汤，用开水代替</li><li>香料：八角、桂皮、香叶、白芷、白蔻、花椒、干辣椒</li><li>起锅烧油，油热加入生姜葱炸香，关小火加入豆瓣酱、黄豆酱（没有就算了）炒香，倒入牛肉</li><li>沿着锅边倒入生抽、黄酒（料酒）、生抽、然后倒入准备好的香料，炒香后，加热水</li><li>调味：盐、白糖、胡椒粉，调好后，转小火炖 90 分钟，中途加其他的菜</li></ol><h1 id="泡椒鸡杂" tabindex="-1">泡椒鸡杂 <a class="header-anchor" href="#泡椒鸡杂" aria-label="Permalink to “泡椒鸡杂”">​</a></h1><ol><li>鸡杂切片，越薄越好，切好后多洗几遍，把血水洗干净，挤干水分</li><li>加盐、胡椒粉、黄酒抓一下腌一下，再少来点淀粉抓一下，放一边</li><li>准备泡生姜、泡辣椒，切颗粒，芹菜，葱段啥的</li><li>大火烧油，油热倒入鸡杂，一变色就倒出来</li><li>再烧油，炸点花椒，迅速下入泡椒泡姜，炒一下，加入豆瓣酱，炒香</li><li>倒入鸡杂、调料：老抽、生抽（锅边倒入）、鸡精、味精、白糖</li><li>倒入芹菜葱段之类的，最后再来一点锅边醋</li></ol>',13)])])}const m=i(o,[["render",t]]);export{f as __pageData,m as default};
